#include<bits/stdc++.h>
using namespace std;
bool fanwei(int x,int l,int r)
{
    return l<=x&&x<=r;
}
struct ip
{
    int a,b,c,d,e;
    bool operator<(const ip&y)const
    {
        if(a==y.a)
        {
            if(b==y.b)
            {
                if(c==y.c)
                {
                    if(d==y.d)
                    {
                        return e<y.e;
                    }
                    return d<y.d;
                }
                return c<y.c;
            }
            return b<y.b;
        }
        return a<y.a;
    }
};
map<ip,int> mp;
bool tiqu(string s,int &a,int &b,int &c,int &d,int &e)
{
    int n=s.length();
    int flag=1,num=0;
    for(int i=0;i<n;i++)
    {
        if(s[i]=='.')
        {
            if(flag>=4||i==n-1||i==0||s[i-1]=='.'||s[i-1]=='.')
            {
                return false;
            }
            if(flag==1)
            {
                a=num;
            }
            else if(flag==2)
            {
                b=num;
            }
            else if(flag==3)
            {
                c=num;
            }
            num=0;
            flag++;
            continue;
        }
        if(s[i]==':')
        {
            if(flag!=4||i==n-1||i==0||s[i-1]=='.'||s[i-1]=='.')
            {
                return false;
            }
            d=num;
            num=0;
            flag++;
            continue;
        }
        if((i==0||s[i-1]=='.'||s[i-1]==':')&&s[i]=='0')
        {
            return false;
        }
        num=num*10+s[i]-'0';
    }
    if(flag!=5)
    {
        return false;
    }
    e=num;
    return true;
}
int main()
{
    int t;
    scanf("%d",&t);
    for(int id=1;id<=t;id++)
    {
        string str;
        cin>>str;
        string s1;
        cin>>s1;
        int a,b,c,d,e;
        if(!tiqu(s1,a,b,c,d,e))
        {
            printf("ERR\n");
            continue;
        }
        // printf("a=%d b=%d c=%d d=%d e=%d\n",a,b,c,d,e);
        if(!(fanwei(a,0,255)&&fanwei(b,0,255)&&fanwei(c,0,255)&&fanwei(d,0,255)&&fanwei(e,0,65535)))
        {
            printf("ERR\n");
            continue;
        }
        ip p=(ip){a,b,c,d,e};
        if(str=="Server")
        {
            if(mp[p])
            {
                printf("FAIL\n");
            }
            else
            {
                mp[p]=id;
                printf("OK\n");
            }
        }
        else
        {
            if(mp[p])
            {
                printf("%d\n",mp[p]);
            }
            else
            {
                printf("FAIL\n");
            }
        }
    }
    return 0;
}
